      touch_ids_down_ |= (1 << event.pointer_details().id);
      env_->SetTouchDown(touch_ids_down_ != 0);
      break;

    // Handle EventType::kTouchCancelled only if it has a native event.
    case ui::EventType::kTouchCancelled:
      if (!event.HasNativeEvent())
